+                TableOrSubquery::Table { name, alias, .. } => (name.name.clone(), alias.clone()),
+                _ => {
+                    return Err(FrankenError::NotImplemented(
+                        "window functions with non-table source".to_owned(),
+                    ));
+                }
+            },
+            None => {
+                return Err(FrankenError::NotImplemented(
+                    "window functions without FROM".to_owned(),
+                ));
+            }
